import{_ as e,o as a,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const n="/images/lekt6001.jpg",d="/images/lekt6002.jpg",l="/images/lekt6003.jpg",o="/images/lekt6004.jpg",s="/images/lekt6005.jpg",u="/images/lekt6006.jpg",h="/images/lekt6007.jpg",p="/images/lekt6008.jpg",m="/images/lekt6009.jpg",y=JSON.parse('{"title":"Lektion 60","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion60.md","filePath":"lektionen/lektion60.md"}'),c={name:"lektionen/lektion60.md"};function b(k,t,f,q,g,w){return a(),i("div",null,[...t[0]||(t[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-60" tabindex="-1">Lektion 60 <a class="header-anchor" href="#lektion-60" aria-label="Permalink to &quot;Lektion 60&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>60.1. Die Perfektendungen des Dual (द्विवचनम्)</li><li>60.2. Der Dual des reduplizierten Perfekt (द्वित्वलिट्) <ul><li>60.2.1. Typ 1: keine Stammabstufung</li><li>60.2.2. Typ 2: starker Stamm Hochstufe, schwacher Stamm Tiefstufe</li><li>60.2.3. Typ 3: Starker Stamm Hochstufe/Dehnstufe <ul><li>60.2.3.1. Typ 3a: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe</li><li>60.2.3.2. Typ 3b: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe</li></ul></li><li>60.2.4. Typ 4: Wurzeln auf -ā / -ai</li><li>60.2.5. Typ 5: Konsonant-a-Konsonant <ul><li>60.2.5.1. Typ 5a: Konsonant-a-Konsonant, schwacher Stamm Tiefstufe</li><li>60.2.5.2. Typ 5b: Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h, Schwacher Stamm ohne Reduplikation, mit -e-</li><li>60.2.5.3. Typ 5c: Konsonant-a-Konsonant, schwacher Stamm Hochstufe</li></ul></li></ul></li><li>60.3. Der Dual des periphrastischen Perfekt (अनुप्रयोगलिट्)</li><li>60.4. Das Partizip परस्मैपद des reduplizierten Perfekt (द्वित्वलिट्)</li><li>60.5. Deklination der Stämme auf -añc (-ac) <ul><li>60.5.1. Dreistämmige Stämme auf -añc</li><li>60.5.2. Zweistämmige Stämme auf -añc</li></ul></li><li>60.6. Das Desiderativum (सन्) <ul><li>60.6.1. Bildung des Desiderativstammes</li><li>60.6.2. Konjugation des Desiderativs (सन्)</li></ul></li><li>60.7. Übung</li></ul><h2 id="_60-1-die-perfektendungen-des-dual-द्विवचनम्" tabindex="-1">60.1. Die Perfektendungen des Dual (द्विवचनम्) <a class="header-anchor" href="#_60-1-die-perfektendungen-des-dual-द्विवचनम्" aria-label="Permalink to &quot;60.1. Die Perfektendungen des Dual (द्विवचनम्)&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>-va</td><td>-vahe</td></tr><tr><td>2. मध्यमः</td><td>-athur</td><td>-āthe</td></tr><tr><td>3. प्रथमः</td><td>-atur</td><td>-āte</td></tr></tbody></table><h2 id="_60-2-der-dual-des-reduplizierten-perfekt-द्वित्वलिट्" tabindex="-1">60.2. Der Dual des reduplizierten Perfekt (द्वित्वलिट्) <a class="header-anchor" href="#_60-2-der-dual-des-reduplizierten-perfekt-द्वित्वलिट्" aria-label="Permalink to &quot;60.2. Der Dual des reduplizierten Perfekt (द्वित्वलिट्)&quot;">​</a></h2><h3 id="_60-2-1-typ-1-keine-stammabstufung" tabindex="-1">60.2.1. Typ 1: keine Stammabstufung <a class="header-anchor" href="#_60-2-1-typ-1-keine-stammabstufung" aria-label="Permalink to &quot;60.2.1. Typ 1: keine Stammabstufung&quot;">​</a></h3><p>बन्ध् 9P &quot;binden&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>बबन्धिव</td></tr><tr><td>2. मध्यमः</td><td>बबन्धथुर्</td></tr><tr><td>3. प्रथमः</td><td>बबन्धतुर्</td></tr></tbody></table></blockquote><p>भाष् 1Ā &quot;sprechen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>बभाषिवहे</td></tr><tr><td>2. मध्यमः</td><td>बभाषाथे</td></tr><tr><td>3. प्रथमः</td><td>बभाषाते</td></tr></tbody></table></blockquote><h3 id="_60-2-2-typ-2-starker-stamm-hochstufe-schwacher-stamm-tiefstufe" tabindex="-1">60.2.2. Typ 2: starker Stamm Hochstufe, schwacher Stamm Tiefstufe <a class="header-anchor" href="#_60-2-2-typ-2-starker-stamm-hochstufe-schwacher-stamm-tiefstufe" aria-label="Permalink to &quot;60.2.2. Typ 2: starker Stamm Hochstufe, schwacher Stamm Tiefstufe&quot;">​</a></h3><p>भिद् 7U &quot;spalten&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>बिभिदिव</td><td>बिभिदिवहे</td></tr><tr><td>2. मध्यमः</td><td>बिभिदथुर्</td><td>बिभिदाथे</td></tr><tr><td>3. प्रथमः</td><td>बिभिदतुर्</td><td>बिभिदाते</td></tr></tbody></table></blockquote><h3 id="_60-2-3-typ-3-starker-stamm-hochstufe-dehnstufe" tabindex="-1">60.2.3. Typ 3: Starker Stamm Hochstufe/Dehnstufe <a class="header-anchor" href="#_60-2-3-typ-3-starker-stamm-hochstufe-dehnstufe" aria-label="Permalink to &quot;60.2.3. Typ 3: Starker Stamm Hochstufe/Dehnstufe&quot;">​</a></h3><h4 id="_60-2-3-1-typ-3a-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-tiefstufe" tabindex="-1">60.2.3.1. Typ 3a: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe <a class="header-anchor" href="#_60-2-3-1-typ-3a-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-tiefstufe" aria-label="Permalink to &quot;60.2.3.1. Typ 3a: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe&quot;">​</a></h4><p>नी 1U &quot;führen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>निन्यिव</td><td>निन्यिवहे</td></tr><tr><td>2. मध्यमः</td><td>निन्यथुर्</td><td>निन्याथे</td></tr><tr><td>3. प्रथमः</td><td>निन्यतुर्</td><td>निन्याते</td></tr></tbody></table></blockquote><p>स्तु 2U (अनिट्) &quot;loben&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>तुष्टुव</td><td>तुष्तुवहे</td></tr><tr><td>2. मध्यमः</td><td>तुष्टुवथुर्</td><td>तुष्टुवाथे</td></tr><tr><td>3. प्रथमः</td><td>तुष्टुवतुर्</td><td>तुष्टुवाते</td></tr></tbody></table></blockquote><p>कृ 8U (अनिट्) &quot;tun, machen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>चकृव</td><td>चकृवहे</td></tr><tr><td>2. मध्यमः</td><td>चक्रथुर्</td><td>चक्राथे</td></tr><tr><td>3. प्रथमः</td><td>चक्रतुर्</td><td>चक्राते</td></tr></tbody></table></blockquote><h4 id="_60-2-3-2-typ-3b-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-hochstufe" tabindex="-1">60.2.3.2. Typ 3b: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe <a class="header-anchor" href="#_60-2-3-2-typ-3b-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-hochstufe" aria-label="Permalink to &quot;60.2.3.2. Typ 3b: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe&quot;">​</a></h4><p>स्मृ 1P &quot;vergegenwärtigen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>सस्मरिव</td></tr><tr><td>2. मध्यमः</td><td>सस्मरथुर्</td></tr><tr><td>3. प्रथमः</td><td>सस्मरतुर्</td></tr></tbody></table></blockquote><h3 id="_60-2-4-typ-4-wurzeln-auf-a-ai" tabindex="-1">60.2.4. Typ 4: Wurzeln auf -ā / -ai <a class="header-anchor" href="#_60-2-4-typ-4-wurzeln-auf-a-ai" aria-label="Permalink to &quot;60.2.4. Typ 4: Wurzeln auf -ā / -ai&quot;">​</a></h3><p>दा 3U &quot;geben&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>ददिव</td><td>ददिवहे</td></tr><tr><td>2. मध्यमः</td><td>ददथुर्</td><td>ददाथे *</td></tr><tr><td>3. प्रथमः</td><td>ददतुर्</td><td>ददाते *</td></tr></tbody></table><p>* identisch mit den entsprechenden Formen des Indikativ Präsens!</p></blockquote><h3 id="_60-2-5-typ-5-konsonant-a-konsonant" tabindex="-1">60.2.5. Typ 5: Konsonant-a-Konsonant <a class="header-anchor" href="#_60-2-5-typ-5-konsonant-a-konsonant" aria-label="Permalink to &quot;60.2.5. Typ 5: Konsonant-a-Konsonant&quot;">​</a></h3><h4 id="_60-2-5-1-typ-5a-konsonant-a-konsonant-schwacher-stamm-tiefstufe" tabindex="-1">60.2.5.1. Typ 5a: Konsonant-a-Konsonant, schwacher Stamm Tiefstufe <a class="header-anchor" href="#_60-2-5-1-typ-5a-konsonant-a-konsonant-schwacher-stamm-tiefstufe" aria-label="Permalink to &quot;60.2.5.1. Typ 5a: Konsonant-a-Konsonant, schwacher Stamm Tiefstufe&quot;">​</a></h4><p>गम् 1U &quot;gehen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>जग्मिव</td><td>जग्मिवहे</td></tr><tr><td>2. मध्यमः</td><td>जग्मथुर्</td><td>जग्माथे</td></tr><tr><td>3. प्रथमः</td><td>जग्मतुर्</td><td>जग्माते</td></tr></tbody></table></blockquote><h4 id="_60-2-5-2-typ-5b-konsonant-a-konsonant-anfangskonsonant-kein-guttural-aspirat-h-schwacher-stamm-ohne-reduplikation-mit-e" tabindex="-1">60.2.5.2. Typ 5b: Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h, Schwacher Stamm ohne Reduplikation, mit -e- <a class="header-anchor" href="#_60-2-5-2-typ-5b-konsonant-a-konsonant-anfangskonsonant-kein-guttural-aspirat-h-schwacher-stamm-ohne-reduplikation-mit-e" aria-label="Permalink to &quot;60.2.5.2. Typ 5b: Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h, Schwacher Stamm ohne Reduplikation, mit -e-&quot;">​</a></h4><p>पच् 1U &quot;garen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>पेचिव</td><td>पेचिवहे</td></tr><tr><td>2. मध्यमः</td><td>पेचथुर्</td><td>पेचाथे</td></tr><tr><td>3. प्रथमः</td><td>पेचतुर्</td><td>पेचाते</td></tr></tbody></table></blockquote><h4 id="_60-2-5-3-typ-5c-konsonant-a-konsonant-schwacher-stamm-hochstufe" tabindex="-1">60.2.5.3. Typ 5c: Konsonant-a-Konsonant, schwacher Stamm Hochstufe <a class="header-anchor" href="#_60-2-5-3-typ-5c-konsonant-a-konsonant-schwacher-stamm-hochstufe" aria-label="Permalink to &quot;60.2.5.3. Typ 5c: Konsonant-a-Konsonant, schwacher Stamm Hochstufe&quot;">​</a></h4><p>क्रम् 1U &quot;schreiten&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>चक्रमिव</td><td>चक्रमिवहे</td></tr><tr><td>2. मध्यमः</td><td>चक्रमथुर्</td><td>चक्रमाथे</td></tr><tr><td>3. प्रथमः</td><td>चक्रमतुर्</td><td>चक्रमाते</td></tr></tbody></table></blockquote><h2 id="_60-3-der-dual-des-periphrastischen-perfekt-अनुप्रयोगलिट्" tabindex="-1">60.3. Der Dual des periphrastischen Perfekt (अनुप्रयोगलिट्) <a class="header-anchor" href="#_60-3-der-dual-des-periphrastischen-perfekt-अनुप्रयोगलिट्" aria-label="Permalink to &quot;60.3. Der Dual des periphrastischen Perfekt (अनुप्रयोगलिट्)&quot;">​</a></h2><p>गण् 10P &quot;zählen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>परस्मैपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>गणयां चकृव</td></tr><tr><td>गणयामासिव</td><td></td></tr><tr><td>गणयां बभूविव</td><td></td></tr><tr><td>2. मध्यमः</td><td>गणयां चक्रथुर्</td></tr><tr><td>गणयामासथुर्</td><td></td></tr><tr><td>गणयां बभूवथुर्</td><td></td></tr><tr><td>3. प्रथमः</td><td>गणयां चक्रतुर्</td></tr><tr><td>गणयामासतुर्</td><td></td></tr><tr><td>गणयां बभूवतुर्</td><td></td></tr></tbody></table></blockquote><p>आस् 2Ā &quot;sitzen&quot;</p><blockquote><table tabindex="0"><thead><tr><th></th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>1. तृतीयः</td><td>आसां चकृवहे</td></tr><tr><td>आसामासिव</td><td></td></tr><tr><td>आसां बभूविवव्</td><td></td></tr><tr><td>2. मध्यमः</td><td>आसांव् चक्राथे</td></tr><tr><td>आसामासथुर्</td><td></td></tr><tr><td>आसां बभूवथुर्</td><td></td></tr><tr><td>3. प्रथमः</td><td>आसां चक्राते</td></tr><tr><td>आसामासतुर्</td><td></td></tr><tr><td>आसां बभूवतुर्व्</td><td></td></tr></tbody></table></blockquote><h2 id="_60-4-das-partizip-परस्मैपद-des-reduplizierten-perfekt-द्वित्वलिट्" tabindex="-1">60.4. Das Partizip परस्मैपद des reduplizierten Perfekt (द्वित्वलिट्) <a class="header-anchor" href="#_60-4-das-partizip-परस्मैपद-des-reduplizierten-perfekt-द्वित्वलिट्" aria-label="Permalink to &quot;60.4. Das Partizip परस्मैपद des reduplizierten Perfekt (द्वित्वलिट्)&quot;">​</a></h2><blockquote><p>Bildung:</p><p>schwacher Perfektstamm + vāṃs</p><p>Besteht der schwache Perfektstamm nur aus einer Silbe, dann wird der Bindevokal -i- angefügt. Bei einigen Perfekta ist der Bindevokal wahlweise.</p></blockquote><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>भिद् 7U</th><th>बिभिद्वांस् &quot;jemand, der gespalten hat&quot;</th></tr></thead><tbody><tr><td>अस् 2P; 4P</td><td>आसिवांस् &quot;jemand, der gewesen ist&quot; ; &quot;jemand, der geworfen hat&quot;</td></tr><tr><td>दा 3U</td><td>ददिवांस् (da-d-i-vāṃs) &quot;jemand, der gegeben hat&quot;</td></tr><tr><td>पच् 1U</td><td>पेचिवांस् &quot;jemand, der gegart hat&quot;</td></tr><tr><td>गम् 1U</td><td>जग्मिवांस् / जगन्वांस् &quot;jemand, der gegangen ist&quot;</td></tr></tbody></table></blockquote><p>Deklination:</p><ul><li>starker Stamm: -vāṃs</li><li>schwacher Stamm: <ul><li>vor Konsonant: -vat (!)</li><li>vor Vokal: -uṣ</li></ul></li></ul><p>Vor uṣ entfällt der Bindevokal -i-.</p><p>Feminin:</p><p>schwacher Stamm vor Vokal + -ī (wie देवी dekliniert)</p><p>Beispiel: विदुषी &quot;eine Wissende&quot;</p><p>Paradigmen siehe Kielhorn, Grammatik § 124:</p><p><img src="'+n+'" alt=""></p><p><img src="'+d+'" alt=""></p><h2 id="_60-5-deklination-der-stamme-auf-anc-ac" tabindex="-1">60.5. Deklination der Stämme auf -añc (-ac) <a class="header-anchor" href="#_60-5-deklination-der-stamme-auf-anc-ac" aria-label="Permalink to &quot;60.5. Deklination der Stämme auf -añc (-ac)&quot;">​</a></h2><p>Die Stämme auf -añc/-ac sind Verbindungen von Präverbien usw. mit dem Wurzelnomen der Wurzel अञ्च् / अच् 1U &quot;sich bewegen&quot;.</p><h3 id="_60-5-1-dreistammige-stamme-auf-anc" tabindex="-1">60.5.1. Dreistämmige Stämme auf -añc <a class="header-anchor" href="#_60-5-1-dreistammige-stamme-auf-anc" aria-label="Permalink to &quot;60.5.1. Dreistämmige Stämme auf -añc&quot;">​</a></h3><p>Bildung:</p><ul><li>starker Stamm: -añc</li><li>schwacher Stamm: <ul><li>vor Konsonant: -ac</li><li>vor Vokal: <ul><li>das -a- des schwachen Stamms -ac entfällt und für einen vorangehenden Halbvokal wird der diesem entsprechende lange Vokal substituiert:<br> प्रत्यच् » प्रतीच्<br> अन्वच् » अनूच्</li><li>Geht dem -ac kein Halbvokal voraus, wird -ac durch -īc ersetzt:<br> उदच् » उदीच्</li><li>तिर्यञ्च् » तिरश्</li></ul></li></ul></li></ul><p>Femininum:</p><p>schwacher Stamm vor Vokal + -ī (wie देवी dekliniert)</p><p>Beispiel: प्रतीची</p><h4 id="paradigmen-siehe-kielhorn-grammatik-§-128" tabindex="-1">Paradigmen siehe Kielhorn, Grammatik § 128: <a class="header-anchor" href="#paradigmen-siehe-kielhorn-grammatik-§-128" aria-label="Permalink to &quot;Paradigmen siehe Kielhorn, Grammatik § 128:&quot;">​</a></h4><p><img src="'+l+'" alt=""></p><p><img src="'+o+'" alt=""></p><p>Hierher gehören:</p><ul><li><p>प्रत्यञ्च् 3 &quot;rückwärts, westlich&quot;</p></li><li><p>अन्वञ्च् 3 &quot;folgend&quot;</p></li><li><p>उदञ्च् 3 &quot;nach oben gerichtet, nördlich&quot;</p></li><li><p>तिर्यञ्च् 3 &quot;wagrecht gehend (von Tieren&quot;</p></li><li><p>सम्यञ्च् 3 &quot;richtig&quot;</p></li><li><p>न्यञ्च् 3 &quot;niedrig&quot;</p></li><li><p>विष्वञ्च् 3 &quot;nach allen Seiten gehend&quot;</p></li></ul><h3 id="_60-5-2-zweistammige-stamme-auf-anc" tabindex="-1">60.5.2. Zweistämmige Stämme auf -añc <a class="header-anchor" href="#_60-5-2-zweistammige-stamme-auf-anc" aria-label="Permalink to &quot;60.5.2. Zweistämmige Stämme auf -añc&quot;">​</a></h3><p>Bildung:</p><ul><li>starker Stamm: -añc</li><li>schwacher Stamm vor Konsonant bzw. Vokal: -ac</li></ul><p>Hierher gehören:</p><ul><li>प्राञ्च् 3 &quot;vorwärts gerichtet, östlich&quot;</li><li>अवाञ्च् 3 &quot;abwärts gerichtet&quot;</li></ul><p>Paradigma प्राञ्च् siehe oben!</p><p>|   | उदञ्च् 3<br> &quot;nach oben gerichtet,<br> nördlich&quot; |   | | --- | --- | --- |Die Haupthimmelsrichtungen | प्रत्यञ्च् 3<br> &quot;rückwärts,<br> westlich&quot; | <img src="'+s+'" alt=""> | प्राञ्च् 3<br> &quot;vorwärts gerichtet,<br> östlich&quot; | |   | दक्षिण 3<br> rechts,<br> südlich |   |</p><p>[Bildquelle: paul adrian. -- <a href="http://www.flickr.com/photos/81189455@N00/114519366/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/81189455@N00/114519366/</a>. -- Zugriff am 2009-03-06. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h2 id="_60-6-das-desiderativum-सन्" tabindex="-1">60.6. Das Desiderativum (सन्) <a class="header-anchor" href="#_60-6-das-desiderativum-सन्" aria-label="Permalink to &quot;60.6. Das Desiderativum (सन्)&quot;">​</a></h2><p>Von jeder Wurzel sowie vom Kausativum kann ein Desiderativum (सन्) gebildet werden. Das Desiderativum kann in allen Zeiten und Modi des P, Ā und Passiv konjugiert werde. Desiderativformen außerhalb des Präsensstamms sind aber sehr selten.</p><p>Bedeutung:</p><ul><li>eine Person oder Sache wünscht zu tun oder zu erleiden, was durch die Wurzel oder das Kausativum ausgedrückt wird</li><li>seltener: jemand oder etwas ist im Begriffe, zu tun, was durch die Wurzel oder das Kausativum ausgedrückt wird</li></ul><h4 id="beispiele" tabindex="-1">Beispiele: <a class="header-anchor" href="#beispiele" aria-label="Permalink to &quot;Beispiele:&quot;">​</a></h4><blockquote><table tabindex="0"><thead><tr><th>कृ 8U</th><th>चिकीर्षति &quot;er wünscht zu tun&quot;</th></tr></thead><tbody><tr><td>पत् 1P</td><td>पिपतिषति &quot;er ist im Begriffe, zu fallen&quot;</td></tr><tr><td>चुर् 10U</td><td>चुचोरयिषति &quot;er wünscht zu stehlen&quot;</td></tr><tr><td>बुध् Kaus.</td><td>बुबोधयिषति &quot;er wünscht zu belehren (zur Erkenntnis zu wecken)&quot;</td></tr></tbody></table></blockquote><h3 id="_60-6-1-bildung-des-desiderativstammes" tabindex="-1">60.6.1. Bildung des Desiderativstammes <a class="header-anchor" href="#_60-6-1-bildung-des-desiderativstammes" aria-label="Permalink to &quot;60.6.1. Bildung des Desiderativstammes&quot;">​</a></h3><p>Wurzeln der Präsensklassen 1 - 9:</p><p>reduplizierte Wurzel + sa</p><p>oder:</p><p>reduplizierte Wurzel + i + ṣa</p><p>Die Regeln zur Verwendung des Bindevokals -i- siehe bei Kielhorn, Grammatik § 443 - 445.</p><p>Wurzeln der 10. Präsensklasse und Kausative:</p><p>reduplizierter Präsensstamm + i + ṣa</p><p>Gestalt der Wurzel:</p><ol><li>Die Wurzel ist meist tiefstufig: जीव् » जिजीविष- <ol><li>auslautendes -i, -u wird durch -ī bzw. -ū ersetzt, wenn kein Bindevokal folgt:<br> जि » जिगीष- &quot;zu siegen wünschen&quot;<br> द्रु » दुद्रूष- &quot;zu laufen wünschen&quot;</li><li>auslautendes -ṛ, -ṝ wird durch -īr, nach Labialen durch -ūr ersetzt, wenn kein Bindevokal folgt:<br> कृ » चिकीर्ष- &quot;zu tun wünschen&quot;<br> मृ » मुमूर्ष- &quot;im Begriff sein, zu sterben&quot;<br> पॄ » पुपूर्ष- &quot;zu füllen wünschen&quot;</li><li>दा, धा, मा und einige andere Wurzeln auf -ā, -e, -o haben Tiefstufe Ø:<br> दा » दित्स- (di-d + sa)<br> धा » धित्स-<br> मा » मित्स-</li></ol></li><li>Hochstufige Wurzel haben im Desiderativ: <ol><li>die meisten Wurzeln auf -ā (-e, -ai usw.):<br> गै » जिगास- &quot;zu singen wünschen&quot;<br> पा » पिपास- &quot;zu trinken wünschen, dürsten&quot;</li><li>die meisten Wurzeln der Form (Konsonant -) a / ā - Konsonant:<br> दह् » दिधक्ष- &quot;zu verbrennen wünschen&quot;<br> खाद् » चिखादिष- &quot;zu kauen wünschen&quot;</li><li>bei Antreten des Bindevokals -i-: <ol><li>obligatorisch: Wurzeln der Form i/u - Konsonant sowie (Konsonant -) ṛ/ḷ - Konsonant:<br> इष् » एषिषिष- &quot;zu wünschen verlangen&quot;<br> कॢप् » चिकल्पिष- &quot;passend zu sein wünschen&quot;<br> स्मि » सिस्मयिष- &quot;zu lächeln wünschen&quot;</li><li>wahlweise: Wurzeln der Form Konsonant - (Konsonant -) i/u - Konsonant außer -v_<br> द्युत् » दिद्योतिष- / दिद्युतिष- &quot;aufzublitzen wünschen&quot;</li></ol></li></ol></li></ol><p>Zur Reduplikation:</p><ol><li>Konsonantisch anlautende Wurzeln: Die Reduplikation erfolgt an den nach obigen Regeln veränderten Wurzeln nach den üblichen Regeln. Statt a als Reduplikationsvokal erschein aber i:<br> पा » पिपास-<br> त्यज् » तित्यज-<br> चुर् » चुचोरयिष-<br> Die Zerebralisierung nach i/u von auslautendem -s der Wurzel unterbleibt, wenn das s des Desiderativsuffixes zerebralisiert wird:<br> स्मि » सिस्मयिष-</li><li>Vokalisch anlautende Wurzeln werden nach den entsprechenden Regeln für den reduplizierten Aorist (<a href="./lektion56">Lektion 56</a>) redupliziert:<br> इष् » एषिषिष- (eṣ-i-ṣ-i-ṣa)<br> ईक्ष » ईचिक्षिष- (ī-c-i-kṣ-i-ṣa)<br> ऋ » अरिरिष-</li><li>Die besondere Desiderativbildung bestimmter Wurzeln siehe bei Kielhorn, Grammatik § 451.</li></ol><p>Zu einigen Wurzeln werden Desiderative ohne desiderative Bedeutung gebildet. Zu diesen Desiderativen können Desiderative mit desiderativer Bedeutung gebildet werden.</p><p>Liste bei Kielhorn, Grammatik § 452:</p><p><img src="'+u+'" alt=""></p><h3 id="_60-6-2-konjugation-des-desiderativs-सन्" tabindex="-1">60.6.2. Konjugation des Desiderativs (सन्) <a class="header-anchor" href="#_60-6-2-konjugation-des-desiderativs-सन्" aria-label="Permalink to &quot;60.6.2. Konjugation des Desiderativs (सन्)&quot;">​</a></h3><p>Das Desiderativ ist - mit wenigen Ausnahmen - P, Ā bzw. U, je nachdem, ob die zugrundeliegende Wurzel (bzw. der zugrundeligende Verbalstamm) P, Ā oder U ist.</p><p>Präsensstamm: Konjugation wie ein thematischer Stamm:</p><p>यज् 1U:</p><blockquote><p>P: यियक्षति &quot;er wünscht, für jemand anderen zu opfern&quot;<br> Ā: यियक्षते &quot;er wünscht, für sich selbst (als Opferherr) zu opfern&quot;<br> Passiv: यियक्ष्यते &quot;es wird zu opfern gewünscht&quot;</p></blockquote><p>Perfekt: periphrastisch:</p><blockquote><p>आप् » ईप्स- » ईप्सां चकार &quot;er wünschte zu erlangen&quot;</p></blockquote><p>Aorist: iṣ-Aorist:</p><blockquote><p>आप् » ऐप्सिषम् (a + īps-i-ṣ-am)</p></blockquote><p>Futur: सेट्</p><blockquote><p>आप् » ईप्सिष्यामि</p></blockquote><p>Zur Bildung von Nomina agentis auf -u aus dem Desiderativstamm siehe <a href="./lektion54">Lektion 54</a>.</p><h2 id="_60-7-ubung" tabindex="-1">60.7. Übung <a class="header-anchor" href="#_60-7-ubung" aria-label="Permalink to &quot;60.7. Übung&quot;">​</a></h2><p>A) Lernen Sie in Kielhorn, Grammatik § 451 die unregelmäßigen Desiderativbildungen zu bisher gelernten Verben:</p><p><img src="'+h+'" alt=""></p><p><img src="'+p+'" alt=""></p><p><img src="'+m+'" alt=""></p><p>B) Bestimmen und übersetzen Sie ohne Hilfsmittel folgende Formen:</p><ol><li><p>ददुषोः</p></li><li><p>अहिंसीः</p></li><li><p>देमथुः</p></li><li><p>वक्त्वा</p></li><li><p>अक्षथाः</p></li><li><p>मुमुषिषिष्यतः</p></li><li><p>अचिक्षंसेथाम्</p></li><li><p>अस्नाः</p></li><li><p>जिहिंसुषि</p></li><li><p>जिहिंसिषुणा</p></li><li><p>द्युभिः</p></li><li><p>जग्लिव</p></li><li><p>अतिस्तीर्षम्</p></li><li><p>अस्मेष्ठाः</p></li><li><p>ईशिष्व</p></li><li><p>रुरुषतुः</p></li><li><p>रुरुषुः</p></li><li><p>रुरुषिषुः</p></li><li><p>अपिप्रीणताम्</p></li><li><p>अपिप्रीषतम्</p></li><li><p>पिप्रियतुः</p></li><li><p>तिस्रः</p></li><li><p>अदांक्ष्टाम्</p></li><li><p>असिसीर्ष्यत</p></li><li><p>बभासाते</p></li><li><p>बिभासिषेथे</p></li><li><p>अबीभणत</p></li><li><p>चकर्त</p></li><li><p>चकर्थ</p></li><li><p>दिद्युते</p></li><li><p>दिद्युतिषे</p></li><li><p>चुच्यूषवे</p></li><li><p>दित्सामि</p></li><li><p>अचीकृतम्</p></li><li><p>विजिगीषौ</p></li><li><p>पित्सेथे</p></li><li><p>उदीचि</p></li><li><p>संगणय्य</p></li><li><p>अतिस्तराव</p></li><li><p>त्रिलोक्याः</p></li><li><p>अहः</p></li><li><p>जग्मुषः</p></li><li><p>अताप्स्व</p></li><li><p>ईशिशिषाञ्चक्रे</p></li><li><p>ईशाञ्चक्रे</p></li><li><p>ईशयाञ्चक्रे</p></li><li><p>षण्णाम्</p></li><li><p>अघुक्षम्</p></li><li><p>अष्टौ</p></li><li><p>प्साथः</p></li><li><p>अवाचः</p></li><li><p>ईयुषे</p></li></ol>',118)])])}const _=e(c,[["render",b]]);export{y as __pageData,_ as default};
